// Слияние основных артистов из БД и похожих из Last.fm
const artistMap = new Map();

const dbItems = $items("Postgres (Get Favorite Artists)");
for (const item of dbItems) {
  if (item.json.name) {
    artistMap.set(item.json.name.toLowerCase(), {
      name: item.json.name,
      source: 'favorite',
      match_reason: 'Ваш любимый артист'
    });
  }
}

const lastfmItems = $items("Last.fm (Similar Artists)");
for (const item of lastfmItems) {
  const similar = item.json.similarartists?.artist || [];
  for (const a of similar) {
    const key = a.name.toLowerCase();
    if (!artistMap.has(key)) {
      artistMap.set(key, {
        name: a.name,
        source: 'similar',
        match_reason: 'Похож на ваших любимых исполнителей'
      });
    }
  }
}

return Array.from(artistMap.values()).map(a => ({ json: a }));

// Фильтр релизов за последние 7 дней из iTunes API
const releases = [];
const now = new Date();
const sevenDaysAgo = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);

for (const item of $input.all()) {
  const results = item.json.results || [];
  for (const album of results) {
    if (album.releaseDate) {
      const releaseDate = new Date(album.releaseDate);
      if (releaseDate >= sevenDaysAgo) {
        releases.push({
          json: {
            artist: album.artistName,
            title: album.collectionName,
            release_type: album.collectionType === 'Album' ? 'album' : 'single',
            source: 'taste',
            url: album.collectionViewUrl || null,
            release_date: album.releaseDate.split('T')[0],
            match_reason: 'Из вашего списка любимых артистов'
          }
        });
      }
    }
  }
}
return releases;

