// Парсинг JSON ответа Gemini и фильтрация релизов
const results = [];
for (const item of $input.all()) {
  try {
    const text = item.json.candidates[0].content.parts[0].text.trim().replace(/```json|```/g, '');
    const parsed = JSON.parse(text);
    if (parsed.is_release && parsed.confidence >= 0.6 && parsed.artist && parsed.title) {
      results.push({
        json: {
          artist: parsed.artist,
          title: parsed.title,
          release_type: parsed.release_type,
          source: item.json._channel === 'cloudeluxe' ? 'ru_cloud' : 'us_rap',
          url: item.json._link || null
        }
      });
    }
  } catch (e) {
    // Пропуск в случае ошибки парсинга
  }
}
return results;

